sp_widget.client_script:
api.controller = function(spUtil) {
    var c = this;

    c.data = c.data || {};
    c.data.appointments = c.data.appointments || [];
    c.filteredAppointments = [];

    c.searchQuery = '';
    c.filterStatus = ''; 
    c.currentPage = 1;
    c.pageSize = 8; 
    c.totalPages = 1;


    c.showModal = false;
    c.showCheckInModal = false;
    c.isCheckInSuccess = false; 
    c.selectedAppt = {};
    c.checkInData = {};
    c.newPatientData = {};

    var statusMap = {
        'scheduled': 'Scheduled',
        'completed': 'Completed',
        'cancelled': 'Cancelled'
    };

    c.getStatusLabel = function(val) {
        if (!val) return 'Unknown';
        return statusMap[val.toString().toLowerCase()] || val;
    };

    c.updateLocalFilters = function() {
        var rawData = c.data.appointments || [];

        c.filteredAppointments = rawData.filter(function(item) {
            var matchSearch = true;
            if (c.searchQuery) {
                var term = c.searchQuery.toLowerCase();
                var patMatch = item.patient && item.patient.toLowerCase().includes(term);
                var docMatch = item.doctor && item.doctor.toLowerCase().includes(term);
                matchSearch = patMatch || docMatch;
            }

            var matchStatus = true;
            if (c.filterStatus) {
                var stat = item.status ? item.status.toLowerCase() : '';
                matchStatus = (stat === c.filterStatus);
            }

            return matchSearch && matchStatus;
        });

        c.totalPages = Math.ceil(c.filteredAppointments.length / c.pageSize) || 1;
        if (c.currentPage > c.totalPages) {
            c.currentPage = c.totalPages > 0 ? c.totalPages : 1;
        }
    };

    c.updateLocalFilters();

    c.getMin = function(a, b) { return Math.min(a, b); };
    c.prevPage = function() { if (c.currentPage > 1) c.currentPage--; };
    c.nextPage = function() { if (c.currentPage < c.totalPages) c.currentPage++; };

    c.setFilter = function(status) {
        c.filterStatus = status;
        c.currentPage = 1; 
        c.updateLocalFilters(); 
    };


    c.viewDetails = function(appt) {
        c.selectedAppt = angular.copy(appt);
        c.selectedAppt.newStatus = appt.status; 
        c.showModal = true;
    };

    c.closeModal = function() {
        c.showModal = false;
        c.showCheckInModal = false;
        c.selectedAppt = {};
    };

    c.saveStatus = function() {
        c.server.get({
            action: 'update_status',
            sys_id: c.selectedAppt.sys_id,
            newStatus: c.selectedAppt.newStatus
        }).then(function(r) {
            c.showModal = false;
            spUtil.addInfoMessage("Appointment status updated to " + c.getStatusLabel(c.selectedAppt.newStatus));
            c.data.appointments = r.data.appointments || [];
            c.updateLocalFilters();
        });
    };


    c.openCheckIn = function(appt) {
        c.checkInData = angular.copy(appt);
        c.isCheckInSuccess = false; 
        c.showCheckInModal = true;
    };

    c.confirmCheckIn = function() {
        c.server.get({
            action: 'check_in',
            checkInData: c.checkInData
        }).then(function(r) {
            c.newPatientData = r.data.newPatientData;
            c.isCheckInSuccess = true; 

            c.data.appointments = r.data.appointments || [];
            c.updateLocalFilters();
        });
    };

    // --- print id logic ---
    c.printID = function() {
        var printContents = document.getElementById('printable-id').innerHTML;
        var printWindow = window.open('', '_blank', 'width=800,height=600');

        printWindow.document.write('<html><head><title>Print Patient ID</title>');
        printWindow.document.write('<style>');
        printWindow.document.write('body { margin: 0; padding: 40px; display: flex; justify-content: center; font-family: sans-serif; -webkit-print-color-adjust: exact; print-color-adjust: exact; }');
        printWindow.document.write('.id-card-wrapper { position: relative; width: 600px; height: 380px; border-radius: 15px; overflow: hidden; }');
        printWindow.document.write('.id-bg-img { position: absolute; top: 0; left: 0; width: 100%; height: 100%; z-index: 1; }');

        printWindow.document.write('.id-barcode { position: absolute; bottom: 80px; left: 35px; width: 180px; height: 45px; z-index: 2; mix-blend-mode: multiply; transform: scale(0.8); transform-origin: left bottom; }');

        printWindow.document.write('.id-text { position: absolute; z-index: 2; color: #1e293b; font-weight: bold; }');
        printWindow.document.write('.id-number { top: 120px; left: 250px; font-size: 18px; }');
        printWindow.document.write('.id-fullname { top: 175px; left: 250px; font-size: 18px; }');
        printWindow.document.write('.id-age { top: 232px; left: 250px; font-size: 18px; }');
        printWindow.document.write('.id-gender { top: 232px; left: 350px; font-size: 18px; }');
        printWindow.document.write('.id-date { top: 290px; left: 250px; font-size: 18px; }');

        printWindow.document.write('.id-footer { bottom: 18px; left: 15px; font-size: 13px; font-weight: 500; width: 570px; text-align: center; }');

        printWindow.document.write('</style></head><body>');

        printWindow.document.write(printContents);
        printWindow.document.write('</body></html>');
        printWindow.document.close();

        //  Added printWindow.close() after the print command!
        setTimeout(function() {
            printWindow.focus();
            printWindow.print();
            printWindow.close(); 
        }, 800);
    };
};

sp_widget.css:
.sc-appt-wrapper {
  font-family: 'Poppins', 'Inter', system-ui, sans-serif;
  color: #1e293b;
  padding: 20px;
  display: flex;
  flex-direction: column;
  min-height: calc(100vh - 40px);
}

.sc-appt-panel {
  background: #ffffff;
  border-radius: 16px;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.03);
  margin-bottom: 24px;
  border: 1px solid #e2e8f0;
  display: flex;
  flex-direction: column;
  flex-grow: 1; 
  overflow: hidden;
}

.sc-appt-header {
  padding: 20px 24px 16px 24px;
  background-color: #fbfcfe;
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: 16px;
}

.sc-appt-title {
  margin: 0;
  font-size: 18px;
  font-weight: 700;
  color: #1e293b;
}

.sc-appt-search {
  position: relative;
  display: flex;
  align-items: center;
  width: 100%;
  max-width: 320px;
}

.sc-appt-search-icon { position: absolute; left: 16px; color: #94a3b8; }

.sc-appt-input {
  width: 100%; height: 42px; padding: 0 16px 0 44px;
  border: 1px solid #cbd5e1; border-radius: 10px;
  font-size: 13px; color: #1e293b; transition: all 0.2s; font-family: inherit;
}

.sc-appt-input:focus { border-color: #1961ED; outline: none; box-shadow: 0 0 0 3px rgba(25, 97, 237, 0.1); }

.sc-appt-tabs-container {
  padding: 0 24px 20px 24px;
  background-color: #fbfcfe;
  border-bottom: 1px solid #e2e8f0;
}

.sc-appt-tabs {
  display: inline-flex;
  background-color: #f1f5f9;
  padding: 6px;
  border-radius: 12px;
  border: 1px solid #e2e8f0;
  gap: 4px;
  flex-wrap: wrap;
}

.sc-appt-tab {
  background: transparent;
  border: none;
  color: #64748b;
  font-weight: 600;
  font-size: 13px;
  padding: 8px 20px;
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.2s;
  font-family: inherit;
}

.sc-appt-tab:hover:not(.active) { color: #1e293b; background: rgba(255, 255, 255, 0.6); }

.sc-appt-tab.active {
  background: #ffffff;
  color: #1961ED;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}


.sc-appt-table-wrapper { width: 100%; overflow-x: auto; flex-grow: 1;}
.sc-appt-table { width: 100%; border-collapse: collapse; text-align: left; }

.sc-appt-table th { 
  background-color: #ffffff; color: #94a3b8; font-size: 12px; font-weight: 700; 
  text-transform: uppercase; padding: 16px 24px; border-bottom: 1px solid #e2e8f0; letter-spacing: 0.5px;
}

.sc-appt-table td { padding: 16px 24px; border-bottom: 1px solid #f1f5f9; font-size: 14px; vertical-align: middle;}
.sc-appt-table tbody tr { transition: background-color 0.2s; }
.sc-appt-table tbody tr:hover { background-color: #f8fafc; }

.sc-fw-bold { font-weight: 600; color: #1e293b; }
.sc-text-muted { color: #64748b; font-size: 13px; }


.sc-badge {
  padding: 4px 12px; border-radius: 20px; font-size: 11px; font-weight: 700; 
  text-transform: uppercase; letter-spacing: 0.5px; display: inline-block; white-space: nowrap;
}

.badge-scheduled { background: #e0f2fe; color: #0369a1; }   /* Blue */
.badge-completed { background: #dcfce7; color: #15803d; }   /* Green */
.badge-cancelled { background: #fee2e2; color: #b91c1c; }   /* Red */


.sc-btn-view {
  background: #eff6ff; border: 1px solid #bfdbfe; color: #1d4ed8;
  padding: 6px 14px; border-radius: 8px; font-weight: 600; font-size: 12px; cursor: pointer; transition: 0.2s;
}
.sc-btn-view:hover { background: #1961ED; color: #ffffff; border-color: #1961ED; }


.sc-empty-state { text-align: center; padding: 60px 20px; color: #94a3b8; flex-grow: 1; display: flex; flex-direction: column; justify-content: center; align-items: center;}
.sc-empty-state i { font-size: 40px; margin-bottom: 12px; color: #cbd5e1; }
.sc-empty-state p { margin: 0; font-weight: 500; font-size: 14px; }


.sc-pagination-wrapper { 
  display: flex; justify-content: space-between; align-items: center; padding: 20px 24px; border-top: 1px solid #e2e8f0; background: #fff;
  margin-top: auto; 
}
.sc-pagination-info { font-size: 13px; color: #64748b; font-weight: 500; }
.sc-pagination-controls { display: flex; align-items: center; gap: 12px;}
.sc-page-text { font-size: 13px; font-weight: 600; color: #475569; }

.sc-btn-page {
  background: #ffffff; border: 1px solid #e2e8f0; color: #475569; border-radius: 8px; 
  cursor: pointer; transition: all 0.2s; display: flex; align-items: center; justify-content: center; width: 32px; height: 32px;
}
.sc-btn-page:hover:not([disabled]) { background: #f1f5f9; color: #1e293b; }
.sc-btn-page[disabled] { opacity: 0.3; cursor: not-allowed; }


.sc-modal-overlay {
  position: fixed; top: 0; left: 0; width: 100%; height: 100%;
  background: rgba(15, 23, 42, 0.4); backdrop-filter: blur(4px);
  z-index: 9999; display: flex; justify-content: center; align-items: center;
  animation: fadeIn 0.2s ease-out; font-family: 'Poppins', 'Inter', system-ui, sans-serif;
}

.sc-modal {
  background: #ffffff; border-radius: 16px; width: 100%; max-width: 500px;
  box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
  overflow: hidden;
}

.sc-modal-header {
  display: flex; justify-content: space-between; align-items: center;
  padding: 20px 24px; border-bottom: 1px solid #f1f5f9;
}
.sc-modal-header h4 { margin: 0; font-weight: 700; color: #1e293b; font-size: 18px; }
.sc-modal-close { background: none; border: none; color: #94a3b8; font-size: 18px; cursor: pointer; transition: 0.2s; }
.sc-modal-close:hover { color: #ef4444; }

.sc-modal-body { padding: 24px; }


.sc-modal-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 20px;
}

.sc-modal-block { display: flex; flex-direction: column; gap: 4px; }
.sc-modal-block-full { display: flex; flex-direction: column; gap: 6px; }

.sc-modal-body label { 
  font-size: 11px; color: #94a3b8; text-transform: uppercase; font-weight: 700; letter-spacing: 0.5px; margin: 0; 
}
.sc-modal-body p { margin: 0; font-size: 15px; font-weight: 600; color: #1e293b; }

.sc-modal-divider { border-top: 1px solid #f1f5f9; margin: 20px 0; }

.sc-notes-box {
  background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 8px; padding: 16px;
  font-size: 14px; color: #475569; line-height: 1.5; min-height: 80px; white-space: pre-wrap;
}


.sc-modal-select {
  width: 100%; height: 44px; padding: 0 16px; border: 1px solid #cbd5e1;
  border-radius: 10px; font-size: 14px; color: #1e293b; font-family: inherit;
  font-weight: 500; cursor: pointer; background-color: #f8fafc; transition: all 0.2s;
}
.sc-modal-select:focus { border-color: #1961ED; outline: none; box-shadow: 0 0 0 3px rgba(25, 97, 237, 0.1); background-color: #ffffff; }

.sc-modal-footer {
  padding: 16px 24px; background: #fbfcfe; border-top: 1px solid #f1f5f9;
  display: flex; justify-content: flex-end; align-items: center;
}

.sc-btn-default { 
  background: #ffffff; border: 1px solid #cbd5e1; color: #475569; padding: 8px 24px; border-radius: 8px; font-weight: 600; font-size: 13px; cursor: pointer; transition: 0.2s; 
}
.sc-btn-default:hover { background: #f1f5f9; color: #1e293b; }

.sc-btn-primary {
  background: #1961ED; border: none; color: #ffffff; padding: 8px 24px;
  border-radius: 8px; font-weight: 600; font-size: 13px; cursor: pointer; transition: 0.2s;
}
.sc-btn-primary:hover:not([disabled]) { background: #1d4ed8; }
.sc-btn-primary[disabled] { opacity: 0.5; cursor: not-allowed; }

@keyframes fadeIn { from { opacity: 0; transform: scale(0.98); } to { opacity: 1; transform: scale(1); } }
.sc-modal-large {
  max-width: 650px;
}

.sc-modal-alert-info {
  background-color: #eff6ff;
  border: 1px solid #bfdbfe;
  color: #1e3a8a;
  padding: 12px 16px;
  border-radius: 8px;
  display: flex;
  gap: 12px;
  align-items: center;
  font-size: 13px;
  font-weight: 500;
}
.sc-modal-alert-info i { font-size: 18px; color: #3b82f6; }
.sc-modal-alert-info p { margin: 0; line-height: 1.4; }

.sc-success-alert {
  display: flex;
  align-items: center;
  gap: 12px;
  background-color: #ecfdf5;
  border: 1px solid #a7f3d0;
  color: #065f46;
  padding: 16px 20px;
  border-radius: 12px;
  font-weight: 600;
  font-size: 14px;
}
.sc-success-alert i { font-size: 20px; color: #10b981; }


.id-card-preview {
  display: flex;
  justify-content: center;
  margin-top: 20px;
  height: 290px; 
}

.id-card-wrapper {
  position: relative;
  width: 600px;
  height: 380px;
  overflow: hidden;
  border-radius: 15px;
  box-shadow: 0 10px 30px rgba(0,0,0,0.15);
  font-family: 'Inter', system-ui, sans-serif;
}

.id-card-scale {
  transform: scale(0.75);
  transform-origin: top center;
}

.id-bg-img {
  position: absolute;
  top: 0; left: 0;
  width: 100%; height: 100%;
  z-index: 1;
}

.id-barcode {
  position: absolute;
  bottom: 80px;
  left: 35px;
  width: 180px;
  height: 45px;
  z-index: 2;
  mix-blend-mode: multiply;
  transform: scale(0.8);
  transform-origin: left bottom; 
}

.id-text {
  position: absolute;
  z-index: 2;
  color: #1e293b;
  font-weight: bold; 
}

.id-number   { top: 120px; left: 250px; font-size: 18px; } 
.id-fullname { top: 175px; left: 250px; font-size: 18px; } 
.id-age      { top: 228px; left: 250px; font-size: 18px; } 
.id-gender   { top: 228px; left: 350px; font-size: 18px; } 
.id-date     { top: 290px; left: 250px; font-size: 18px; } 

.id-footer {
  bottom: 18px;
  left: 15px;
  font-size: 13px; 
  font-weight: 500;
  width: 570px;
  text-align: center;
  color: #1e293b;
}


.sc-action-group {
  display: flex;
  gap: 8px;
  align-items: center;
}


.sc-btn-checkin {
  background: #dcfce7;
  border: 1px solid #bbf7d0;
  color: #15803d;
  padding: 6px 14px;
  border-radius: 8px;
  font-weight: 600;
  font-size: 12px;
  cursor: pointer;
  transition: 0.2s;
  display: flex;
  align-items: center;
  gap: 6px;
}
.sc-btn-checkin:hover {
  background: #15803d;
  color: #ffffff;
  border-color: #15803d;
}

.sc-btn-success {
  background: #10b981;
  border: none;
  color: #ffffff;
  padding: 8px 24px;
  border-radius: 8px;
  font-weight: 600;
  font-size: 13px;
  cursor: pointer;
  transition: 0.2s;
}
.sc-btn-success:hover:not([disabled]) { background: #059669; }

sp_widget.script:
(function() {
    var userId = gs.getUserID();


    if (input && input.action == 'update_status') {
        var updateGR = new GlideRecord('x_1954503_smartc_0_smartcare_appointment');
        if (updateGR.get(input.sys_id)) {
            updateGR.setValue('status', input.newStatus);
            updateGR.update();
        }
    }


    if (input && input.action == 'check_in') {
        var pGr = new GlideRecord('x_1954503_smartc_0_patient');
        pGr.initialize();

        pGr.setValue('full_name', input.checkInData.patient);
        pGr.setValue('assigned_doctor', input.checkInData.doctor_sys_id);
        pGr.setValue('age', input.checkInData.age); 
        pGr.setValue('gender', input.checkInData.gender); 


        if (input.checkInData.department_value) {
            pGr.setValue('medical_department', input.checkInData.department_value); 
        }

        pGr.setValue('state', 'register'); 

        var newSysId = pGr.insert(); 

        if (newSysId) {
            var fetchNew = new GlideRecord('x_1954503_smartc_0_patient');
            fetchNew.get(newSysId);

            var gd = new GlideDate();
            gd.setValue(fetchNew.getValue('sys_created_on'));
            var formattedDate = gd.getByFormat("dd MMM yyyy");

            data.newPatientData = {
                number: fetchNew.getValue('number'),
                full_name: fetchNew.getValue('full_name'),
                age: fetchNew.getValue('age') || '--',
                gender: fetchNew.getValue('gender') || '--',
                registered_date: formattedDate,
                department: fetchNew.getDisplayValue('medical_department') || 'Unassigned',
                doctor: fetchNew.getDisplayValue('assigned_doctor') || 'Pending',
                nurse: fetchNew.getDisplayValue('u_assigned_nurse') || 'Pending'
            };
        }

        var aGr = new GlideRecord('x_1954503_smartc_0_smartcare_appointment');
        if (aGr.get(input.checkInData.sys_id)) {
            aGr.setValue('status', 'completed');
            aGr.update();
        }
    }

    data.appointments = [];

    var isDoctor = gs.hasRole('x_1954503_smartc_0.doctor');
    var isAdmin = gs.hasRole('admin') || gs.hasRole('x_1954503_smartc_0.admin');

    var apptGR = new GlideRecord('x_1954503_smartc_0_smartcare_appointment');

    if (isDoctor && !isAdmin) {
        apptGR.addQuery('doctor', userId);
    }

    apptGR.orderByDesc('appointment_date');
    apptGR.query();

    while (apptGR.next()) {
        var rawTime = apptGR.getDisplayValue('appointment_time') || 'Not Set';
        var cleanTime = rawTime.replace('1970-01-01 ', ''); 

        var docId = apptGR.getValue('doctor');
        var docDeptDisplay = 'Unassigned';
        var docDeptValueForPatient = '';


        if (docId) {
            var usrGr = new GlideRecord('sys_user');
            if (usrGr.get(docId)) {
                var rawDept = usrGr.getValue('u_medical_department') || '';
                docDeptDisplay = usrGr.getDisplayValue('u_medical_department') || rawDept || 'Unassigned';

                if (rawDept) {

                    docDeptValueForPatient = rawDept.toLowerCase().replace(/ /g, '_');
                }
            }
        }

        data.appointments.push({
            sys_id: apptGR.getUniqueValue(),
            patient: apptGR.getValue('patient') || 'Unknown', 
            age: apptGR.getValue('age') || '--', 
            gender: apptGR.getValue('gender') || '--',

            department: docDeptDisplay,            
            department_value: docDeptValueForPatient, 

            doctor: apptGR.getDisplayValue('doctor') || 'Unassigned', 
            doctor_sys_id: docId, 
            date: apptGR.getDisplayValue('appointment_date') || 'Not Set',
            time: cleanTime, 
            status: (apptGR.getValue('status') || 'scheduled').toLowerCase(),
            notes: apptGR.getValue('notes') || 'No additional notes provided.'
        });
    }
})();
